                                    : 'border-white/5 border-dashed hover:border-emerald-500/40 hover:bg-emerald-900/5'}
                            `}
                        >
                            {/* 密室编号 */}
                            <div className="absolute top-3 left-3 px-2 py-0.5 bg-black/60 rounded border border-white/5 text-[10px] text-gray-500 font-bold group-hover:text-emerald-500 transition-colors">
                                {slotNames[idx % 10]}号密室
                            </div>

                            {/* 聚灵阵特效 */}
                            {member && (
                                <div className="absolute inset-0 pointer-events-none opacity-30">
                                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border border-emerald-500/20 rounded-full animate-[spin_10s_linear_infinite]"></div>
                                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-48 h-48 bg-emerald-500/5 blur-[40px] rounded-full"></div>
                                </div>
                            )}

                            {member ? (
                                <div className="flex flex-col items-center animate-fade-in z-10">
                                    <div className="relative mb-4">
                                        <div className="w-16 h-16 rounded-full bg-emerald-900/40 border-2 border-emerald-500 flex items-center justify-center text-3xl shadow-[0_0_15px_rgba(16,185,129,0.5)]">
                                            🧘
                                        </div>
                                        <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-emerald-600 rounded-full border border-black flex items-center justify-center">
                                            <span className="text-[10px] text-white animate-pulse">✨</span>
