                            ) : (
                                <div className="flex flex-col items-center opacity-40 group-hover:opacity-100 transition-all z-10">
                                    <div className="w-16 h-16 rounded-full border-2 border-dashed border-gray-700 flex items-center justify-center text-3xl mb-4 group-hover:border-emerald-500/50">
                                        🔘
                                    </div>
                                    <p className="text-gray-600 text-[11px] font-bold tracking-widest group-hover:text-emerald-600">虚位以待</p>
                                    <p className="text-[9px] text-gray-700 mt-2 italic group-hover:text-gray-500 transition-colors">点击指派族人</p>
                                </div>
                            )}

                            {/* 悬浮文字 */}
                            <div className="absolute inset-0 bg-emerald-900/10 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                <span className="bg-black/80 px-4 py-2 rounded text-[10px] text-emerald-500 font-bold border border-emerald-500/40 tracking-widest">
                                    {member ? '点击：更换/出关' : '点击：指派入室'}
                                </span>
                            </div>
                        </div>
                    );
                })}
            </div>

            {/* 底部：温馨提示 */}
            <div className="p-4 bg-emerald-900/10 border border-emerald-900/20 rounded-lg text-center">
                <p className="text-[11px] text-gray-500 font-serif leading-relaxed">
                    “修行一途，如逆水行舟。此修炼室依附地脉而建，静心咒阵可助子弟宁神定志，减少走火入魔之虞。”
                </p>
            </div>

            {/* 成员选择弹窗 */}
            {showMemberSelect && (
                <div className="absolute inset-0 z-[60] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-[#1a1a1a] border-2 border-emerald-900/40 w-full max-w-md rounded shadow-2xl flex flex-col max-h-[80%] overflow-hidden animate-fade-in" onClick={(e) => e.stopPropagation()}>
                        <div className="p-4 bg-[#121a15] border-b border-emerald-900/20 flex justify-between items-center">
                            <div>
                                <h4 className="text-emerald-500 font-bold text-sm tracking-widest">指派族人闭关</h4>
                                <p className="text-[10px] text-gray-500 mt-0.5 italic">※ 仅限具备灵根且未在执行任务的族人</p>
                            </div>
                            <button onClick={() => setShowMemberSelect(false)} className="text-gray-500 hover:text-white text-2xl transition-colors font-bold">×</button>
                        </div>
                        <div className="p-2 overflow-y-auto custom-scrollbar flex-1 space-y-1 bg-black/20">
                            {selectedSlotIdx !== null && assignedIds[selectedSlotIdx] && (
                                <button 
                                    onClick={() => handleSelect(null)}
                                    className="w-full p-3 bg-red-900/10 border border-red-900/20 text-red-500 text-xs font-bold hover:bg-red-900/20 mb-2 rounded transition-all"
                                >
                                    令其出关 (设为空位)
                                </button>
                            )}
                            {selectableMembers.length > 0 ? selectableMembers.map(member => (
                                <div 
                                    key={member.id} 
                                    onClick={() => handleSelect(member.id)}
                                    className={`p-3 border rounded transition-all cursor-pointer flex justify-between items-center group
                                        ${selectedSlotIdx !== null && member.id === assignedIds[selectedSlotIdx] 
                                            ? 'bg-emerald-900/20 border-emerald-500/50' 
                                            : 'bg-white/5 border-white/5 hover:bg-emerald-900/10 hover:border-emerald-600/30'}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded bg-black/40 flex items-center justify-center border border-white/5 text-emerald-500 text-xs font-bold">
                                            {member.name[0]}
                                        </div>
                                        <div className="flex flex-col">
                                            <span className="text-gray-200 font-bold text-sm">{member.name}</span>
                                            <span className="text-[10px] text-gray-500">{member.realm}{member.subRealm}层</span>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] text-emerald-600 font-bold uppercase">{member.position}</p>
                                        <p className="text-[9px] text-gray-700 mt-1">{member.age} 岁</p>
                                    </div>
                                </div>
                            )) : (
                                <div className="py-20 text-center text-gray-600 italic text-xs">暂无符合条件的族人</div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CultivationRoomTab;

import React, { useMemo } from 'react';
import { ClanMember, Building, Inventory, Realm } from '../../../../types';
import { ALL_ITEM_DETAILS, REALM_ORDER } from '../../../../constants';
import { getGradeStyle } from '../../../MembersPanel/Shared/utils';
import { renderItemContent } from '../../../Shared/TooltipRenderers';

interface Props {
    building: Building;
    members: ClanMember[];
    inventory: Inventory;
    alreadyAssignedIds: string[];
    onAssignBuilding: (buildingId: string, memberId: string | null) => void;
    showTooltip: (e: React.MouseEvent, content: React.ReactNode) => void;
    hideTooltip: () => void;
}

const LibraryTab: React.FC<Props> = ({ building, members, inventory, alreadyAssignedIds, onAssignBuilding, showTooltip, hideTooltip }) => {
    const aliveMembers = members.filter(m => m.status !== 'dead' && m.family === '望月李氏');
    const assignedCurator = aliveMembers.find(m => m.id === building.assignedMemberId);

    const familyMethods = useMemo(() => {
        // Fix: Cast Object.entries to [string, number][] to ensure count is treated as a number during filter comparison
        return (Object.entries(inventory.methods) as [string, number][])
            .map(([id, count]) => ({ id: parseInt(id), count }))
            .filter(item => item.count > 0);
    }, [inventory.methods]);

    return (
        <div className="flex gap-8 h-full animate-fade-in max-w-5xl mx-auto">
            <div className="w-80 p-6 bg-black/40 border border-amber-900/20 rounded shadow-xl flex flex-col h-fit">
                <h3 className="text-amber-600 font-bold text-lg mb-6 flex items-center gap-2"><span>📚</span> 藏经阁</h3>
                <div className="bg-[#1a1612] p-5 rounded border border-amber-900/30">
                    <div className="flex justify-between items-center mb-6">
                        <p className="text-gray-500 text-[11px] font-bold uppercase tracking-widest shrink-0 mr-4">守阁长老</p>
                        <select className="bg-[#2c1810] border border-yellow-900/40 px-2 py-1 rounded text-yellow-500 outline-none text-[10px] font-bold min-w-[120px] shadow-sm hover:border-yellow-600 transition-colors" 
                            onChange={(e) => onAssignBuilding(building.id, e.target.value || null)} 
                            value={building.assignedMemberId || ''}>
                            <option value="">- 轮空 -</option>
                            {aliveMembers
                                .filter(m => m.realm !== Realm.Mortal && (!alreadyAssignedIds.includes(m.id) || m.id === building.assignedMemberId))
                                .sort((a, b) => {
                                    const realmA = REALM_ORDER.indexOf(a.realm);
                                    const realmB = REALM_ORDER.indexOf(b.realm);
                                    if (realmB !== realmA) return realmB - realmA;
                                    return b.subRealm - a.subRealm;
                                })
                                .map(m => (
                                <option key={m.id} value={m.id}>
                                    {m.name} · {m.realm+m.subRealm}层
                                </option>
                            ))}
                        </select>
                    </div>
                    {assignedCurator ? (
                        <div className="animate-fade-in">
                            <p className="text-yellow-500 font-black text-2xl tracking-tighter">{assignedCurator.name}</p>
                            <p className="text-amber-600 text-[13px] mt-1 font-bold">镇守功法传续</p>
                        </div>
                    ) : <p className="italic text-gray-700 py-10 text-center border border-dashed border-amber-900/20 rounded text-[13px]">暂未任命</p>}
                </div>
            </div>

            <div className="flex-1 bg-black/40 border border-white/5 rounded-xl p-6 flex flex-col overflow-hidden">
                <h4 className="text-amber-500 text-sm font-bold mb-6 flex items-center gap-2 border-b border-white/5 pb-3">
                    <span>📜</span> 家族传承功法
                </h4>
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                    {familyMethods.length > 0 ? (
                        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-6 px-1">
                            {familyMethods.map(item => {
                                const detail = (ALL_ITEM_DETAILS as any)[item.id];
                                if (!detail) return null;

                                const style = getGradeStyle(detail.grade);

                                return (
                                    <div 
                                        key={item.id} 
                                        onMouseEnter={(e) => showTooltip(e, renderItemContent(item.id))}
                                        onMouseLeave={hideTooltip}
                                        className={`${style.bg} border-2 ${style.border} p-3 rounded-lg flex flex-col items-center group transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden cursor-help`}
                                    >
                                        <div className={`text-3xl mt-2 group-hover:scale-110 transition-transform ${style.shadow}`}>📖</div>
                                        <span className={`text-[11px] font-bold text-center truncate w-full mt-2 px-1 ${style.text} ${style.shadow}`}>{detail.name}</span>
                                        <div className="mt-auto">
                                            <span className="text-[11px] font-bold text-yellow-600/80 font-mono">余量：{item.count}</span>
                                        </div>
                                        <div className="absolute top-1 right-1">
                                            <span className={`text-[7px] font-bold px-1 rounded-sm border ${style.border} ${style.text} bg-black/60`}>
                                                {typeof detail.grade === 'number' ? `${detail.grade}品` : detail.grade}
                                            </span>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-gray-700 italic gap-2">
                            <span className="text-4xl opacity-10">📖</span>
                            <p className="text-[13px]">族中目前无任何公有功法存本</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default LibraryTab;

import React, { useState, useMemo } from 'react';
import { Inventory, ClanMember, Realm } from '../../../types';
import { ALL_ITEM_DETAILS, REALM_ORDER } from '../../../constants';
import { getGradeStyle, getRealmText } from '../../MembersPanel/Shared/utils';
import { renderItemContent } from '../../Shared/TooltipRenderers';

interface Props {
    inventory: Inventory;
    members: ClanMember[];
    onAssignItem?: (memberId: string, itemId: number, category: string, quantity: number) => void;
    showTooltip: (e: React.MouseEvent, content: React.ReactNode) => void;
    hideTooltip: () => void;
}

type WarehouseSubTab = 'all' | 'materials' | 'pills' | 'equipment' | 'methods' | 'scrolls';
type SortKey = 'grade' | 'quantity' | 'name' | 'category';

const WarehouseTab: React.FC<Props> = ({ inventory, members, onAssignItem, showTooltip, hideTooltip }) => {
    const [warehouseSubTab, setWarehouseSubTab] = useState<WarehouseSubTab>('all');
    const [warehouseSortKey, setWarehouseSortKey] = useState<SortKey>('category');
    const [focusedItemId, setFocusedItemId] = useState<number | null>(null);

    // 流程控制状态
    const [assigningMemberId, setAssigningMemberId] = useState<string | null>(null);
    const [showMemberSelect, setShowMemberSelect] = useState(false);
    const [showQuantitySelect, setShowQuantitySelect] = useState(false);
    const [showConfirmModal, setShowConfirmModal] = useState(false);

    const [selectedAssignQuantity, setSelectedAssignQuantity] = useState(1);

    const handleTabChange = (tab: WarehouseSubTab) => {
        setWarehouseSubTab(tab);
        if (tab === 'all') {
            setWarehouseSortKey('category');
        } else if (warehouseSortKey === 'category') {
            setWarehouseSortKey('grade');
        }
        setFocusedItemId(null);
    };

    const sortedWarehouseItems = useMemo(() => {
        const inv = inventory;
        const allItems: Array<{ id: number; count: number; category: WarehouseSubTab; inventoryKey: keyof Inventory; icon: string }> = [];

        const addToAll = (record: Record<number, number>, category: WarehouseSubTab, inventoryKey: keyof Inventory, icon: string) => {
            // Fix: Cast Object.entries to [string, number][] to fix type inference issues
            (Object.entries(record) as [string, number][]).forEach(([id, count]) => {
                if (count > 0) allItems.push({ id: parseInt(id), count, category, inventoryKey, icon });
            });
        };

        addToAll(inv.scrolls, 'scrolls', 'scrolls', '📜');
        addToAll(inv.methods, 'methods', 'methods', '📖');
        addToAll(inv.herbs, 'materials', 'herbs', '🌿');
        addToAll(inv.minerals, 'materials', 'minerals', '💎');
        addToAll(inv.pills, 'pills', 'pills', '💊');
        addToAll(inv.weapons, 'equipment', 'weapons', '⚔️');

        const filtered = warehouseSubTab === 'all' 
            ? allItems 
            : allItems.filter(item => item.category === warehouseSubTab);

        return filtered.sort((a, b) => {
            const detailA = (ALL_ITEM_DETAILS as any)[a.id];
            const detailB = (ALL_ITEM_DETAILS as any)[b.id];
            if (!detailA || !detailB) return 0;

            if (warehouseSortKey === 'category') {
                const catOrder: Record<string, number> = { 'methods': 0, 'equipment': 1, 'pills': 2, 'scrolls': 3, 'materials': 4 };
                const orderA = catOrder[a.category] ?? 99;
                const orderB = catOrder[b.category] ?? 99;
                if (orderA !== orderB) return orderA - orderB;
                return (typeof detailB.grade === 'number' ? detailB.grade : 0) - (typeof detailA.grade === 'number' ? detailA.grade : 0);
            } else if (warehouseSortKey === 'grade') {
                const gA = typeof detailA.grade === 'number' ? detailA.grade : 0;
                const gB = typeof detailB.grade === 'number' ? detailB.grade : 0;
                return gB - gA;
            } else if (warehouseSortKey === 'quantity') {
                return b.count - a.count;
            } else {
                return detailA.name.localeCompare(detailB.name, 'zh-CN');
            }
        });
    }, [inventory, warehouseSubTab, warehouseSortKey]);

    const familyMembers = useMemo(() => {
        return members
            .filter(m => m.family === '望月李氏' && m.status !== 'dead' && m.realm !== Realm.Mortal && m.age>=6)
            .sort((a, b) => {
                const idxA = REALM_ORDER.indexOf(a.realm);
                const idxB = REALM_ORDER.indexOf(b.realm);
                if (idxA !== idxB) return idxB - idxA;
                return b.subRealm - a.subRealm;
            });
    }, [members]);

    const handleConfirmAssign = () => {
        if (!onAssignItem || !assigningMemberId || focusedItemId === null) return;
        const item = sortedWarehouseItems.find(i => i.id === focusedItemId);
        if (item) {
            onAssignItem(assigningMemberId, focusedItemId, item.inventoryKey, selectedAssignQuantity);
        }
        resetAssignmentState();
    };

    const resetAssignmentState = () => {
        setShowConfirmModal(false);
        setShowQuantitySelect(false);
        setShowMemberSelect(false);
        setFocusedItemId(null);
        setAssigningMemberId(null);
        setSelectedAssignQuantity(1);
    };

    const handleItemClick = (id: number, canAssign: boolean) => {
        if (!canAssign) {
            setFocusedItemId(null);
            return;
        }
        setFocusedItemId(prev => prev === id ? null : id);
    };

    const currentItem = useMemo(() => sortedWarehouseItems.find(i => i.id === focusedItemId), [sortedWarehouseItems, focusedItemId]);

    return (
        <div className="flex flex-col animate-fade-in max-w-5xl mx-auto h-full min-h-0 relative" onClick={() => !showMemberSelect && !showQuantitySelect && !showConfirmModal && setFocusedItemId(null)}>
            <div className="flex flex-wrap items-center justify-between gap-4 mb-6 shrink-0 border-b border-yellow-900/30 pb-4" onClick={(e) => e.stopPropagation()}>
                <div className="flex gap-1 overflow-x-auto scrollbar-hide">
                    {[
                        { id: 'all', name: '全部', icon: '🏠', activeBg: 'bg-yellow-900/30', activeText: 'text-yellow-500' },
                        { id: 'methods', name: '功法', icon: '📖', activeBg: 'bg-amber-800/20', activeText: 'text-amber-600' },
                        { id: 'equipment', name: '装备', icon: '⚔️', activeBg: 'bg-blue-900/20', activeText: 'text-blue-500' },
                        { id: 'pills', name: '丹药', icon: '💊', activeBg: 'bg-pink-900/20', activeText: 'text-pink-500' },
                        { id: 'scrolls', name: '卷轴', icon: '📜', activeBg: 'bg-amber-800/20', activeText: 'text-amber-500' },
                        { id: 'materials', name: '材料', icon: '💎', activeBg: 'bg-emerald-900/20', activeText: 'text-emerald-500' },
                    ].map(tab => (
                        <button 
                            key={tab.id}
                            onClick={() => handleTabChange(tab.id as any)} 
                            className={`px-4 py-2 rounded text-[13px] font-bold transition-all flex items-center gap-2 border whitespace-nowrap ${warehouseSubTab === tab.id ? `${tab.activeBg} ${tab.activeText} border-yellow-600/50 shadow-lg` : 'bg-black/10 text-gray-600 border-transparent hover:text-gray-400'}`}
                        >
                            <span className="text-base">{tab.icon}</span> {tab.name}
                        </button>
                    ))}
                </div>

                <div className="flex items-center gap-2 bg-black/40 px-3 py-1.5 rounded-lg border border-white/5 shadow-inner">
                    <span className="text-[11px] text-gray-500 font-bold uppercase tracking-widest border-r border-white/10 pr-3">排序</span>
                    <select 
                        value={warehouseSortKey}
                        onChange={(e) => setWarehouseSortKey(e.target.value as SortKey)}
                        className="bg-transparent text-[12px] text-yellow-600 outline-none font-bold cursor-pointer"
                    >
                        {warehouseSubTab === 'all' && <option value="category">类型</option>}
                        <option value="grade">品级</option>
                        <option value="quantity">数量</option>
                        <option value="name">名称</option>
                    </select>
                </div>
            </div>

            <div className="bg-black/30 rounded-lg p-6 border border-white/5 h-[480px] overflow-y-auto custom-scrollbar relative">
                {sortedWarehouseItems.length > 0 ? (
                    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 gap-6">
                        {sortedWarehouseItems.map(item => {
                            const details: any = (ALL_ITEM_DETAILS as any)[item.id];
                            if (!details) return null;
                            const style = getGradeStyle(details.grade);
                            const isFocused = focusedItemId === item.id;
                            const canAssign = item.category === 'equipment' || item.category === 'pills';

                            return (
                                <div key={item.id} className="flex flex-col gap-2 relative">
                                    <div 
                                        onClick={(e) => { e.stopPropagation(); handleItemClick(item.id, canAssign); }}
                                        onMouseEnter={(e) => showTooltip(e, renderItemContent(item.id))}
                                        onMouseLeave={hideTooltip}
                                        className={`${style.bg} border-2 ${isFocused ? 'border-yellow-500 scale-[1.02] shadow-[0_0_20px_rgba(234,179,8,0.2)]' : style.border} p-3 rounded-lg flex flex-col items-center group transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden ${canAssign ? 'cursor-pointer' : 'cursor-default opacity-80'}`}
                                    >
                                        <div className={`text-3xl mt-2 ${canAssign ? 'group-hover:scale-110' : ''} transition-transform`}>{item.icon}</div>
                                        <span className={`text-[12px] font-bold text-center truncate w-full mt-2 px-1 ${style.text}`}>{details.name}</span>
                                        <div className="mt-auto"><span className="text-[11px] font-bold text-yellow-600/80 mt-auto font-mono">数量：{item.count}</span></div>
                                        <div className="absolute top-1 right-1"><span className={`text-[7px] font-bold px-1 rounded-sm border ${style.border} ${style.text} bg-black/60`}>{typeof details.grade === 'number' ? `${details.grade}品` : details.grade}</span></div>
                                    </div>
                                    {isFocused && canAssign && (
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setShowMemberSelect(true); }}
                                            className="bg-yellow-800 text-yellow-100 py-2 rounded text-[11px] font-bold shadow-md hover:bg-yellow-700 transition-all animate-fade-in border border-yellow-600/30"
                                        >分配</button>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="h-full flex flex-col items-center justify-center text-gray-700 italic gap-4">
                        <span className="text-5xl opacity-20">🏯</span>
                        <p className="text-[13px]">家族仓库中尚无此类物资</p>
                    </div>
                )}
            </div>

            {/* 第一步：选择成员 */}
            {showMemberSelect && (
                <div className="absolute inset-0 z-[60] bg-black/70 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-[#1a1310] border-2 border-yellow-900/40 w-full max-w-md rounded shadow-2xl flex flex-col max-h-[85%] overflow-hidden animate-fade-in" onClick={(e) => e.stopPropagation()}>
                        <div className="p-4 bg-[#2c1810] border-b border-yellow-900/20 flex justify-between items-center">
                            <div>
                                <h4 className="text-yellow-500 font-bold text-sm tracking-widest">领受族人</h4>
                                <p className="text-[10px] text-gray-500 mt-0.5 italic">※ 准许族人领用家族资源</p>
                            </div>
                            <button onClick={() => setShowMemberSelect(false)} className="text-gray-500 hover:text-white text-2xl transition-colors font-bold">×</button>
                        </div>
                        <div className="p-4 overflow-y-auto custom-scrollbar flex-1 space-y-2">
                            {familyMembers.length > 0 ? familyMembers.map(member => (
                                <div 
                                    key={member.id} 
                                    onClick={() => { setAssigningMemberId(member.id); setShowMemberSelect(false); setShowQuantitySelect(true); setSelectedAssignQuantity(1); }}
                                    className="p-4 bg-black/40 border border-white/5 rounded-sm hover:bg-yellow-900/10 hover:border-yellow-600/50 transition-all cursor-pointer flex justify-between items-center group"
                                >
                                    <div className="flex items-center gap-4">
                                        <div className="w-8 h-8 rounded-full bg-yellow-900/10 flex items-center justify-center border border-yellow-900/20 text-yellow-600/60 font-bold text-[10px]">{member.gender === '男' ? '♂' : '♀'}</div>
                                        <div className="flex flex-col">
                                            <span className="text-yellow-100 font-bold text-sm">{member.name}</span>
                                            <span className="text-[12px] text-gray-300">{getRealmText(member.realm, member.subRealm)}</span>
                                        </div>
                                    </div>
                                    <div className="flex flex-col items-end">
                                        <span className="text-[12px] text-gray-300 font-bold uppercase tracking-widest mb-1">{member.position}</span>
                                        <span className="text-[10px] text-yellow-600 opacity-0 group-hover:opacity-100 transition-all transform translate-x-2 group-hover:translate-x-0 font-bold">选择该族人 ◈</span>
                                    </div>
                                </div>
                            )) : (
                                <div className="py-20 text-center text-gray-600 italic">族中尚无具备修行资质的在世族人</div>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {/* 第二步：选择数量 */}
            {showQuantitySelect && currentItem && (
                <div className="absolute inset-0 z-[70] bg-black/80 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-[#1a1310] border-2 border-yellow-900/40 w-full max-w-sm rounded shadow-2xl p-6 flex flex-col animate-fade-in" onClick={(e) => e.stopPropagation()}>
                        <h4 className="text-yellow-500 font-bold text-sm tracking-widest mb-6 border-b border-yellow-900/20 pb-2">分配数量</h4>

                        <div className="bg-black/40 p-4 rounded border border-white/5 mb-6 text-center">
                            <p className="text-gray-400 text-xs mb-2 italic">正在向 <span className="text-yellow-500 font-bold">{members.find(m => m.id === assigningMemberId)?.name}</span> 分配</p>
                            <p className="text-yellow-100 font-bold text-lg">{(ALL_ITEM_DETAILS as any)[currentItem.id]?.name}</p>
                        </div>

                        <div className="space-y-4">
                            <div className="flex items-center justify-between">
                                <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">选择数量</span>
                                <span className="text-sm text-yellow-500 font-mono font-bold">{selectedAssignQuantity} / {currentItem.count}</span>
                            </div>
                            <div className="flex items-center gap-4 bg-black/60 p-3 rounded-lg border border-white/5">
                                <button onClick={() => setSelectedAssignQuantity(Math.max(1, selectedAssignQuantity - 1))} className="w-8 h-8 bg-yellow-900/20 text-yellow-500 rounded border border-yellow-900/40 flex items-center justify-center font-bold">-</button>
                                <input 
                                    type="range" min="0" max={currentItem.count} value={selectedAssignQuantity}
                                    onChange={(e) => setSelectedAssignQuantity(parseInt(e.target.value))}
                                    className="flex-1 accent-yellow-600"
                                />
                                <button onClick={() => setSelectedAssignQuantity(Math.min(currentItem.count, selectedAssignQuantity + 1))} className="w-8 h-8 bg-yellow-900/20 text-yellow-500 rounded border border-yellow-900/40 flex items-center justify-center font-bold">+</button>
                            </div>
                            <div className="flex justify-center gap-4">
                                <button onClick={() => setSelectedAssignQuantity(1)} className="text-[10px] text-gray-500 hover:text-yellow-600">最小值</button>
                                <button onClick={() => setSelectedAssignQuantity(currentItem.count)} className="text-[10px] text-gray-500 hover:text-yellow-600">全部</button>
                            </div>
                        </div>

                        <div className="flex gap-4 mt-8">
                            <button onClick={() => { setShowQuantitySelect(false); setShowMemberSelect(true); }} className="flex-1 py-2 bg-black/40 border border-gray-700 text-gray-500 rounded text-xs font-bold hover:text-gray-300">上一步</button>
                            <button onClick={() => { setShowQuantitySelect(false); setShowConfirmModal(true); }} className="flex-1 py-2 bg-yellow-900/60 border border-yellow-500 text-yellow-100 rounded text-xs font-bold hover:bg-yellow-800 shadow-lg">下一步</button>
                        </div>
                    </div>
                </div>
            )}

            {/* 第三步：最终确认弹窗 */}
            {showConfirmModal && currentItem && (
                <div className="fixed inset-0 z-[100] bg-black/85 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-[#1a1310] border-4 border-[#4a3728] p-8 rounded-sm shadow-2xl max-w-sm w-full text-center relative overflow-hidden" onClick={(e) => e.stopPropagation()}>
                        <div className="absolute top-0 left-0 w-full h-1 bg-yellow-600/30"></div>
                        <h4 className="text-2xl font-cursive text-yellow-500 mb-6 tracking-widest">分 配 诏 令</h4>
                        <div className="bg-black/60 p-6 rounded-sm border border-white/5 mb-8">
                            <p className="text-gray-300 text-sm leading-relaxed font-serif">
                                族中老祖诏曰：<br/><br/>
                                将 <span className="text-yellow-500 font-bold">{(ALL_ITEM_DETAILS as any)[focusedItemId!]?.name}</span> x<span className="text-yellow-500 font-bold">{selectedAssignQuantity}</span> 分配给族人 <span className="text-yellow-500 font-bold">{members.find(m => m.id === assigningMemberId)?.name}</span> 掌管。
                            </p>
                            <p className="text-[10px] text-gray-600 mt-4 italic border-t border-white/5 pt-2">※ 家族内府将不再记录该物品流向</p>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => { setShowConfirmModal(false); setShowQuantitySelect(true); }} className="flex-1 py-2.5 bg-black/40 border border-[#4a3728] text-gray-500 rounded-sm font-bold hover:text-gray-300 transition-all text-xs tracking-widest">驳回重审</button>
                            <button onClick={handleConfirmAssign} className="flex-1 py-2.5 bg-yellow-900/80 text-yellow-100 rounded-sm font-bold hover:bg-yellow-800 transition-all shadow-xl text-xs tracking-widest border border-yellow-600/30">准奏</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default WarehouseTab;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { ClanMember, Inventory } from '../../../types';
import { ALL_ITEM_DETAILS } from '../../../constants';
import { getGradeStyle } from '../Shared/utils';

interface Props {
    member: ClanMember;
    onUsePill: (id: number, qty: number) => void;
    onEquip: (id: number, cat: 'weapon' | 'armor' | 'accessory' | 'treasure') => void;
    onContributeItem: (itemId: number, category: string, quantity: number) => void;
    onViewMethod?: () => void;
    showTooltip: (e: React.MouseEvent, content: React.ReactNode) => void;
    hideTooltip: () => void;
    renderItemTooltip: (id: number) => React.ReactNode;
}

type BagSubTab = 'all' | 'methods' | 'equipment' | 'pills' | 'scrolls' | 'materials';
type SortKey = 'grade' | 'quantity' | 'name' | 'category';
type ActionType = 'use' | 'contribute' | null;

const BagTab: React.FC<Props> = ({ member, onUsePill, onEquip, onContributeItem, onViewMethod, showTooltip, hideTooltip, renderItemTooltip }) => {
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('category');
    const [focusedItem, setFocusedItem] = useState<number | null>(null);

    // 弹窗状态
    const [showActionModal, setShowActionModal] = useState(false);
    const [modalAction, setModalAction] = useState<ActionType>(null);
    const [modalItem, setModalItem] = useState<{ id: number; count: number; inventoryKey: keyof Inventory } | null>(null);
    const [selectedQty, setSelectedQty] = useState(1);
    const [isFinalConfirm, setIsFinalConfirm] = useState(false);

    const listRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (event.target === listRef.current) {
                setFocusedItem(null);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const handleTabChange = (tab: BagSubTab) => {
        setBagSubTab(tab);
        if (tab === 'all') {
            setBagSortKey('category');
        } else if (bagSortKey === 'category') {
            setBagSortKey('grade');
        }
        setFocusedItem(null);
    };

    const sortedItems = useMemo(() => {
        const inv = member.personalInventory;
        const itemsList: Array<{ id: number; count: number; category: BagSubTab; inventoryKey: keyof Inventory }> = [];
        // Fix: Explicitly cast entries to [string, number][] to fix potential 'unknown' type inference in filter/map
        const add = (rec: Record<number, number>, cat: BagSubTab, invKey: keyof Inventory) => (Object.entries(rec) as [string, number][]).forEach(([id, count]) => count > 0 && itemsList.push({ id: parseInt(id), count, category: cat, inventoryKey: invKey }));

        if (bagSubTab === 'all' || bagSubTab === 'methods') add(inv.methods, 'methods', 'methods');
        if (bagSubTab === 'all' || bagSubTab === 'equipment') add(inv.weapons, 'equipment', 'weapons');
        if (bagSubTab === 'all' || bagSubTab === 'pills') add(inv.pills, 'pills', 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'scrolls') add(inv.scrolls, 'scrolls', 'scrolls');
        if (bagSubTab === 'all' || bagSubTab === 'materials') { 
            add(inv.herbs, 'materials', 'herbs'); 
            add(inv.minerals, 'materials', 'minerals'); 
        }

        return itemsList.sort((a, b) => {
            const dA = (ALL_ITEM_DETAILS as any)[a.id];
            const dB = (ALL_ITEM_DETAILS as any)[b.id];
            if (!dA || !dB) return 0;

            if (bagSortKey === 'category') {
                const catOrder: Record<string, number> = { 'methods': 0, 'equipment': 1, 'pills': 2, 'scrolls': 3, 'materials': 4 };
                const orderA = catOrder[a.category] ?? 99;
                const orderB = catOrder[b.category] ?? 99;
                if (orderA !== orderB) return orderA - orderB;
                return (typeof dB.grade === 'number' ? dB.grade : 0) - (typeof dA.grade === 'number' ? dA.grade : 0);
            }
            if (bagSortKey === 'grade') {
                return (typeof dB.grade === 'number' ? dB.grade : 0) - (typeof dA.grade === 'number' ? dA.grade : 0);
            }
            if (bagSortKey === 'quantity') return b.count - a.count;

            return dA.name.localeCompare(dB.name, 'zh-CN');
        });
    }, [member, bagSubTab, bagSortKey]);

    const initiateAction = (item: { id: number, count: number, category: BagSubTab; inventoryKey: keyof Inventory }, action: ActionType) => {
        const details = (ALL_ITEM_DETAILS as any)[item.id];
        if (!details) return;

        if (action === 'use') {
            if (item.category === 'pills' && item.count > 1) {
                setModalItem(item);
                setModalAction('use');
                setSelectedQty(1);
                setIsFinalConfirm(false);
                setShowActionModal(true);
            } else if (item.category === 'pills') {
                onUsePill(item.id, 1);
                setFocusedItem(null);
            } else if (item.category === 'equipment') {
                let cat: 'weapon' | 'armor' | 'accessory' | 'treasure' = 'weapon';
                if (details.name.includes('佩') || details.name.includes('戒') || details.name.includes('镯')) cat = 'accessory';
                else if (details.name.includes('甲') || details.name.includes('袍')) cat = 'armor';
                else if (details.name.includes('印') || details.name.includes('镜') || details.name.includes('壶')) cat = 'treasure';
                onEquip(item.id, cat);
                setFocusedItem(null);
            } else if (item.category === 'methods') {
                if (onViewMethod) onViewMethod();
                setFocusedItem(null);
            }
        } else if (action === 'contribute') {
            setModalItem(item);
            setModalAction('contribute');
            setSelectedQty(1);
            setIsFinalConfirm(false);
            setShowActionModal(true);
        }
        hideTooltip();
    };

    const confirmModalAction = () => {
        if (!modalItem || !modalAction) return;

        // 如果是上交且还没有进行最终确认，则切换到最终确认状态
        if (modalAction === 'contribute' && !isFinalConfirm) {
            setIsFinalConfirm(true);
            return;
        }

        if (modalAction === 'use') {
            onUsePill(modalItem.id, selectedQty);
        } else if (modalAction === 'contribute') {
            onContributeItem(modalItem.id, modalItem.inventoryKey, selectedQty);
        }

        setShowActionModal(false);
        setFocusedItem(null);
        setIsFinalConfirm(false);
    };

    return (
        <div className="h-full flex flex-col min-h-0 animate-fade-in pr-2 overflow-hidden relative">
            <div className="flex flex-wrap items-center justify-between gap-4 mb-4 shrink-0" onClick={(e) => e.stopPropagation()}>
                <div className="flex gap-2 p-1 bg-black/40 rounded-xl border border-yellow-900/20">
                    {(['all', 'methods', 'equipment', 'pills', 'scrolls', 'materials'] as BagSubTab[]).map(t => (
                        <button key={t} onClick={() => handleTabChange(t)} className={`px-4 py-1.5 text-[10px] rounded-lg transition-all font-bold ${bagSubTab === t ? 'bg-yellow-700 text-white' : 'text-gray-500 hover:text-gray-300'}`}>
                            {t === 'all' ? '📦 全部' : t === 'methods' ? '📖 功法' : t === 'equipment' ? '🏮 装备' : t === 'pills' ? '💊 丹药' : t === 'scrolls' ? '📜 卷轴' : '🎋 材料'}
                        </button>
                    ))}
                </div>
                <div className="flex items-center gap-2 bg-black/40 px-2 py-1 rounded-lg border border-white/5">
                    <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest border-r border-white/10 pr-2">排序</span>
                    <select value={bagSortKey} onChange={(e) => setBagSortKey(e.target.value as SortKey)} className="bg-bg-panel text-[10px] text-yellow-600 outline-none font-bold cursor-pointer">
                        {bagSubTab === 'all' && <option value="category">按类型</option>}
                        <option value="grade">按品级</option>
                        <option value="quantity">按数量</option>
                        <option value="name">按名称</option>
                    </select>
                </div>
            </div>

            <div 
                ref={listRef}
                className="flex-1 overflow-y-auto custom-scrollbar pb-10"
            >
                {sortedItems.length > 0 ? (
                    <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-5 gap-x-4 gap-y-8 items-start pointer-events-none">
                        {sortedItems.map(item => {
                            const details = (ALL_ITEM_DETAILS as any)[item.id];
                            if (!details) return null;

                            const style = getGradeStyle(details.grade);
                            const isRestricted = details.requiredRealm && member.realm !== details.requiredRealm;
                            const isFocused = focusedItem === item.id;

                            return (
                                <div key={item.id} className="flex flex-col gap-[5px] pointer-events-auto">
                                    <div 
                                        onClick={(e) => { e.stopPropagation(); setFocusedItem(isFocused ? null : item.id); }} 
                                        onMouseEnter={(e) => showTooltip(e, renderItemTooltip(item.id))} 
                                        onMouseLeave={hideTooltip} 
                                        className={`${style.bg} border-2 ${isFocused ? 'border-yellow-500 scale-[1.02]' : style.border} ${style.glow} p-3 rounded-lg flex flex-col items-center aspect-[4/5] justify-between shadow-lg relative group overflow-hidden transition-all duration-200 cursor-pointer ${isRestricted ? 'opacity-50 grayscale' : ''}`}
                                    >
                                        <div className={`text-3xl mt-2 group-hover:scale-110 transition-transform ${style.shadow}`}>
                                            {item.category === 'equipment' ? '⚔️' : item.category === 'pills' ? '💊' : item.category === 'materials' ? '💎' : item.category === 'scrolls' ? '📜' : '📖'}
                                        </div>
                                        <span className={`text-[11px] font-bold text-center truncate w-full mt-2 px-1 ${style.text} ${style.shadow}`}>{details.name}</span>
                                        <span className="text-[11px] font-bold text-yellow-600/80 font-mono">数量：{item.count}</span>
                                    </div>

                                    {isFocused && (
                                        <div 
                                            className="bg-black/95 border border-yellow-900/40 rounded-lg p-1.5 w-full max-w-full min-w-0 flex flex-col gap-1.5 animate-fade-in z-20 shadow-xl"
                                            onClick={(e) => e.stopPropagation()}
                                        >
                                            <div className="flex flex-col gap-1 w-full">
                                                <div className="flex gap-2 w-full">
                                                    {item.category !== 'materials' && item.category !== 'scrolls' && (
                                                        <button 
                                                            onClick={() => isRestricted ? null : initiateAction(item, 'use')} 
                                                            disabled={isRestricted}
                                                            className={`flex-1 whitespace-nowrap text-center text-white text-[10px] leading-tight py-1 px-1 rounded font-bold ${style.bg.replace('40', '90')} border ${style.border} active:scale-95 transition-all shadow-lg hover:brightness-125 disabled:opacity-30`}
                                                        >
                                                            {item.category === 'pills' ? '使用' : item.category === 'equipment' ? '佩戴' : '修炼' }
                                                        </button>
                                                    )}
                                                    <button 
                                                        onClick={() => initiateAction(item, 'contribute')} 
                                                        className="flex-1 whitespace-nowrap text-center text-yellow-500 text-[10px] leading-tight py-1 px-1 rounded font-bold bg-yellow-900/20 border border-yellow-600/40 active:scale-95 transition-all shadow-lg hover:bg-yellow-900/40"
                                                    >
                                                        上交
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                ) : (
                    <div className="w-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl flex flex-col items-center gap-4">
                        <span className="text-5xl opacity-10">🎒</span>
                        <span>行囊空空如也</span>
                    </div>
                )}
            </div>

            {/* 操作弹窗 (数量选择 & 确认) */}
            {showActionModal && modalItem && (
                <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-[#1a1310] border-4 border-[#4a3728] p-8 rounded-sm shadow-2xl max-w-sm w-full text-center relative overflow-hidden" onClick={(e) => e.stopPropagation()}>
                        <div className="absolute top-0 left-0 w-full h-1 bg-yellow-600/30"></div>
                        <h4 className="text-2xl font-cursive text-yellow-500 mb-6 tracking-widest">
                            {modalAction === 'use' ? '服用灵丹' : '收回物品'}
                        </h4>

                        <div className="bg-black/60 p-6 rounded-sm border border-white/5 mb-8">
                            {!isFinalConfirm ? (
                                <>
                                    <div className="flex flex-col items-center gap-2 mb-4">
                                        <span className="text-3xl">{(ALL_ITEM_DETAILS as any)[modalItem.id]?.category === 'pills' ? '💊' : '📦'}</span>
                                        <p className="text-yellow-500 font-bold text-lg">{(ALL_ITEM_DETAILS as any)[modalItem.id]?.name}</p>
                                    </div>

                                    <p className="text-gray-400 text-xs mb-6 font-serif leading-relaxed">
                                        {modalAction === 'use' 
                                            ? `确定要消耗该丹药以精进修为吗？` 
                                            : `确定要将此物收回，由家族掌控吗？`}
                                    </p>

                                    {(modalItem.count > 1 || modalAction === 'contribute') && (
                                        <div className="space-y-3">
                                            <div className="flex items-center justify-between px-2">
                                                <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">选择数量</span>
                                                <span className="text-[12px] text-yellow-500 font-mono font-bold">
                                                    {selectedQty} / {modalItem.count}
                                                </span>
                                            </div>
                                            <div className="flex items-center gap-3 bg-white/5 p-2 rounded border border-white/10">
                                                <button 
                                                    onClick={() => setSelectedQty(Math.max(1, selectedQty - 1))}
                                                    className="w-10 h-10 flex items-center justify-center bg-black/40 text-yellow-500 hover:text-yellow-400 rounded border border-white/5 active:scale-90 transition-all font-bold text-lg"
                                                >-</button>
                                                <input 
                                                    type="range"
                                                    min="0"
                                                    max={modalItem.count}
                                                    value={selectedQty}
                                                    onChange={(e) => setSelectedQty(parseInt(e.target.value))}
                                                    className="flex-1 accent-yellow-600"
                                                />
                                                <button 
                                                    onClick={() => setSelectedQty(Math.min(modalItem.count, selectedQty + 1))}
                                                    className="w-10 h-10 flex items-center justify-center bg-black/40 text-yellow-500 hover:text-yellow-400 rounded border border-white/5 active:scale-90 transition-all font-bold text-lg"
                                                >+</button>
                                            </div>
                                            <div className="flex justify-center gap-2">
                                                <button onClick={() => setSelectedQty(1)} className="text-[9px] text-gray-600 hover:text-gray-400 px-2">最小</button>
                                                <button onClick={() => setSelectedQty(modalItem.count)} className="text-[9px] text-gray-600 hover:text-gray-400 px-2">最大</button>
                                            </div>
                                        </div>
                                    )}
                                </>
                            ) : (
                                <div className="animate-fade-in flex flex-col items-center">
                                    <div className="text-4xl mb-4">📜</div>
                                    <p className="text-yellow-500 font-bold text-lg mb-2">确认收回</p>
                                    <p className="text-gray-300 text-sm font-serif leading-relaxed">
                                        您确定要将 <span className="text-white font-bold">{selectedQty}</span> 个 <span className="text-yellow-400 font-bold">{(ALL_ITEM_DETAILS as any)[modalItem.id]?.name}</span> 收回吗？
                                    </p>
                                </div>
                            )}
                        </div>

                        <div className="flex gap-4">
                            <button 
                                onClick={() => {
                                    if (isFinalConfirm) {
                                        setIsFinalConfirm(false);
                                    } else {
                                        setShowActionModal(false);
                                    }
                                }}
                                className="flex-1 py-2.5 bg-black/40 border border-[#4a3728] text-gray-500 rounded-sm font-bold hover:text-gray-300 transition-all text-xs tracking-widest"
                            >
                                {isFinalConfirm ? '返回' : '取消'}
                            </button>
                            <button 
                                onClick={confirmModalAction}
                                className={`flex-1 py-2.5 rounded-sm font-bold transition-all shadow-xl text-xs tracking-widest border border-white/10
                                    ${modalAction === 'use' ? 'bg-blue-900/80 text-blue-100 hover:bg-blue-800' : 'bg-yellow-900/80 text-yellow-100 hover:bg-yellow-800'}`}
                            >
                                {isFinalConfirm ? '确认收回' : '确定'}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default BagTab;

import React, { useState, useMemo } from 'react';
import { ClanMember, Building, Realm, GameState } from '../../../../types';
import { REALM_ORDER } from '../../../../constants';

interface Props {
    building: Building;
    members: ClanMember[];
    alreadyAssignedIds: string[];
    onAssignBuilding: (buildingId: string, memberId: string | null, slotIndex?: number) => void;
    // 假设这些来自父组件或通过 context 获取，为了演示完整性，我们在内部模拟或假设存在
    spiritStones?: number;
}

const CultivationRoomTab: React.FC<Props> = ({ building, members, alreadyAssignedIds, onAssignBuilding }) => {
    const [selectedSlotIdx, setSelectedSlotIdx] = useState<number | null>(null);
    const [showMemberSelect, setShowMemberSelect] = useState(false);

    const aliveMembers = members.filter(m => m.status !== 'dead' && m.family === '望月李氏');

    // 密室配置：甲乙丙三等，每等天地玄黄四级，共12个坑位
    const TIERS = [
        { id: 'Jia', name: '甲等', bonus: 1.5, color: 'text-amber-400', border: 'border-amber-500/40', bg: 'bg-amber-900/10' },
        { id: 'Yi', name: '乙等', bonus: 1.25, color: 'text-blue-400', border: 'border-blue-500/30', bg: 'bg-blue-900/5' },
        { id: 'Bing', name: '丙等', bonus: 1.1, color: 'text-emerald-400', border: 'border-emerald-500/20', bg: 'bg-emerald-900/5' }
    ];
    const SUB_GRADES = ['天', '地', '玄', '黄'];

    // 生成所有密室位元数据
    const allSlots = useMemo(() => {
        const slots = [];
        for (let t = 0; t < TIERS.length; t++) {
            for (let s = 0; s < SUB_GRADES.length; s++) {
                slots.push({
                    tierIdx: t,
                    gradeIdx: s,
                    name: `${SUB_GRADES[s]}字${TIERS[t].name}`,
                    tier: TIERS[t]
                });
            }
        }
        return slots;
    }, []);

    // 1级开放丙等天/地/玄 (索引8,9,10)；2级开放乙等+丙等全开...
    const unlockedCount = useMemo(() => {
        if (building.level === 1) return 3; // 丙等前三
        if (building.level === 2) return 6; // 丙等全开 + 乙等前二
        return 12; // 全开
    }, [building.level]);

    // 修炼室槽位逻辑：固定12个槽位数组，根据建筑等级判断是否可见/锁定
    const assignedIds = useMemo(() => {
        const base = building.assignedMemberIds || [];
        const full = Array(12).fill(null);
