    return (
        <div className="flex gap-6 h-full animate-fade-in max-w-7xl mx-auto overflow-hidden">

            {/* 左侧：灵脉与供能面板 */}
            <div className="w-64 shrink-0 flex flex-col gap-6">
                <div className="p-5 bg-black/40 border border-emerald-900/20 rounded shadow-xl flex flex-col">
                    <h3 className="text-emerald-500 font-bold text-[13px] mb-6 flex items-center gap-2 border-b border-emerald-900/10 pb-2">
                        <span>💠</span> 灵脉概况
                    </h3>

                    <div className="space-y-4">
                        <div className="relative h-20 w-full rounded bg-emerald-900/10 border border-emerald-500/20 overflow-hidden flex flex-col items-center justify-center">
                            <div className="absolute inset-0 bg-gradient-to-b from-emerald-500/5 to-transparent animate-pulse"></div>
                            <span className="text-[10px] text-emerald-500 font-bold tracking-widest uppercase">微型灵脉 (初阶)</span>
                            <span className="text-[9px] text-gray-600 mt-1">灵气活跃度: 盈满</span>
                        </div>

                        <div className="space-y-1.5">
                            <div className="flex justify-between items-center text-[10px]">
                                <span className="text-gray-500 font-medium">地脉基础加成</span>
                                <span className="text-emerald-500 font-bold">+25%</span>
                            </div>
                            <div className="flex justify-between items-center text-[10px]">
                                <span className="text-gray-500 font-medium">灵石聚灵加成</span>
                                <span className="text-yellow-600">待启用</span>
                            </div>
                        </div>

                        <div className="pt-4 border-t border-white/5">
                            <button className="w-full py-2.5 bg-yellow-900/20 border border-yellow-700/30 text-yellow-500 rounded text-[10px] font-bold hover:bg-yellow-900/40 transition-all">
                                ✨ 消耗 100 灵石聚灵
                            </button>
                            <p className="text-[8px] text-gray-700 mt-2 text-center italic">瞬间为所有闭关者提供修为补偿</p>
                        </div>
                    </div>
                </div>

                <div className="p-5 bg-black/40 border border-blue-900/20 rounded shadow-xl flex-1 overflow-hidden flex flex-col">
