                                        const slotIdx = tIdx * 4 + gIdx;
                                        const isUnlocked = isSlotUnlocked(gIdx);

                                        // 未解锁的密室不显示
                                        if (!isUnlocked) return null;

                                        const memberId = assignedIds[slotIdx];
                                        const member = aliveMembers.find(m => m.id === memberId);

                                        return (
                                            <div 
                                                key={slotIdx}
                                                onClick={() => handleSlotClick(slotIdx)}
                                                className={`relative h-44 rounded-lg border flex flex-col items-center justify-center transition-all overflow-hidden group
