export default CultivationRoomTab;

import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, GameEvent } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, ALL_ITEM_DETAILS, RECIPES } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import { CharacterController } from './services/CharacterController';
import { EventController } from './services/EventController';
import ClanDashboard from './components/MembersPanel/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement/ClanManagement';
import BreakthroughModal from './components/Xiulian/BreakthroughModal';
import EventModal from './components/events/EventModal';

const SEASON_NAMES = ['', '春', '夏', '秋', '冬'];

const App: React.FC = () => {
    const [state, setState] = useState<GameState>(() => {
        const initializedMembers = INITIAL_MEMBERS.map(m => ({
            ...m,
            rootGrade: CharacterController.getAutoRootGrade(m.roots)
        })) as ClanMember[];

        return {
            year: 1,
            season: 1,
            spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
            merit: CLAN_MASTER_REGISTRY.merit,
            luck: CLAN_MASTER_REGISTRY.luck,
            members: initializedMembers,
            regions: INITIAL_REGIONS,
            buildings: [],
            inventory: CLAN_MASTER_REGISTRY.inventory,
            currentRegionId: '',
            logs: ["太平历初，望月李氏在此立基。"],
            heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
            unlockedPositions: ['家主', '弟子'],
            flags: {},
            eventQueue: [],
            factionReputation: { '魏家': 50, '邵家': 50, '北寒宗': 50 } 
        };
    });

    const [pendingEvents, setPendingEvents] = useState<GameEvent[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === id);
            if (!member) return prev;
            const { updatedMember, logs } = CharacterController.updateMember(member, updates, prev.year);
            let updatedMembers = prev.members.map(m => m.id === id ? updatedMember : m);
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers,
                logs: logs.length > 0 ? [...logs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleUpdateInventory = (updates: Partial<Inventory>) => {
        setState(prev => ({
            ...prev,
            inventory: { ...prev.inventory, ...updates }
        }));
    };

    const handleAssignItem = (memberId: string, itemId: number, category: string, quantity: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            const itemDetail = ALL_ITEM_DETAILS[itemId] as any;
            const catKey = category as keyof Inventory;

            if (!member || !itemDetail || (prev.inventory[catKey] as any)[itemId] < quantity) return prev;

            const newClanInventory = { ...prev.inventory };
            (newClanInventory[catKey] as any)[itemId] -= quantity;
            if ((newClanInventory[catKey] as any)[itemId] === 0) delete (newClanInventory[catKey] as any)[itemId];

            const newMemberInventory = { ...member.personalInventory };
            (newMemberInventory[catKey] as any)[itemId] = ((newMemberInventory[catKey] as any)[itemId] || 0) + quantity;

            const updatedMembers = prev.members.map(m => 
                m.id === memberId ? { ...m, personalInventory: newMemberInventory } : m
            );

            return {
                ...prev,
                inventory: newClanInventory,
                members: updatedMembers,
                logs: [`【分配】家族将 ${itemDetail.name} x${quantity} 分配给了 ${member.name}。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleContributeItem = (memberId: string, itemId: number, category: string, quantity: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            const catKey = category as keyof Inventory;
            const currentQty = (member.personalInventory[catKey] as any)[itemId] || 0;
            if (currentQty < quantity) return prev;

            const newMemberInventory = { ...member.personalInventory };
            (newMemberInventory[catKey] as any)[itemId] -= quantity;
            if ((newMemberInventory[catKey] as any)[itemId] <= 0) {
                delete (newMemberInventory[catKey] as any)[itemId];
            }

            const newClanInventory = { ...prev.inventory };
            if (catKey !== 'paper') {
                (newClanInventory[catKey] as any)[itemId] = ((newClanInventory[catKey] as any)[itemId] || 0) + quantity;
            }

            const itemDetail = ALL_ITEM_DETAILS[itemId] as any;

            return {
                ...prev,
                inventory: newClanInventory,
                members: prev.members.map(m => m.id === memberId ? { ...m, personalInventory: newMemberInventory } : m),
                logs: [`【上交】${member.name} 将 ${itemDetail?.name || '物品'} x${quantity} 上交给家族。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleNextTurn = async () => {
        setIsProcessing(true);
        await new Promise(resolve => setTimeout(resolve, 800));

        try {
            let turnLogs: string[] = [];
            let newEvents: GameEvent[] = [];
            let finalInventory = { ...state.inventory };

            const currentYear = state.year;
            const currentSeason = state.season;
            const nextSeason = currentSeason >= 4 ? 1 : currentSeason + 1;
            const isYearIncrement = currentSeason === 4;

            // 建筑与生产进度
            const updatedBuildings = state.buildings.map(b => {
                // 处理建造
                if (!b.isFinished) {
                    const rem = b.turnsRemaining - 1;
                    if (rem <= 0) {
                        turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${BUILDING_TYPES[b.type].name} 营造完成。`);
                        return { ...b, isFinished: true, turnsRemaining: 0 };
                    }
                    return { ...b, turnsRemaining: rem };
                }

                // 处理生产 (炼丹/炼器)
                if (b.activeProduction) {
                    const rem = b.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const recipe = [...RECIPES.Alchemy, ...RECIPES.Smithing].find(r => r.id === b.activeProduction!.recipeId);
                        if (recipe) {
                            const productDetail = ALL_ITEM_DETAILS[recipe.productId] as any;
                            const catKey = productDetail.category === 'pill' ? 'pills' : 'weapons';
                            finalInventory[catKey][recipe.productId] = (finalInventory[catKey][recipe.productId] || 0) + 1;
                            turnLogs.push(`【${currentYear}载·成品】${BUILDING_TYPES[b.type].name} 传来阵阵异香，${productDetail.name} 炼制成功！`);
                        }
                        return { ...b, activeProduction: undefined };
                    }
                    return { ...b, activeProduction: { ...b.activeProduction, turnsRemaining: rem } };
                }
                return b;
            });

            const updatedRegions = state.regions.map(r => {
                let nr = { ...r };
                if (nr.activeMission) {
                    const rem = nr.activeMission.turnsRemaining - 1;
                    if (rem <= 0) {
                        const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                        if (member) {
                            const missionEvent = EventController.generateMissionResult(member, nr, currentYear);
                            newEvents.push(missionEvent);
                        }
                        nr.activeMission = undefined;
                    } else {
                        nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                    }
                }
                return nr;
            });

            let guardStones = 0;
            let guardMerit = 0;
            const itemGains: any = { herbs: {}, minerals: {}, pills: {}, weapons: {}, methods: {}, scrolls: {} };
            let hasItemGains = false;

            state.regions.forEach(region => {
                if (region.guardMemberId && region.production) {
                    if (region.production.stones) guardStones += region.production.stones;
                    if (region.production.merit) guardMerit += region.production.merit;
                    if (region.production.items) {
                        Object.entries(region.production.items).forEach(([idStr, qty]) => {
                            const id = parseInt(idStr);
                            const detail = ALL_ITEM_DETAILS[id];
                            if (detail) {
                                const cat = (detail as any).category;
                                const catKey = cat === 'herb' ? 'herbs' :
                                               cat === 'mineral' ? 'minerals' :
                                               cat === 'pill' ? 'pills' :
                                               cat === 'weapon' ? 'weapons' :
                                               cat === 'method' ? 'methods' : 'scrolls';

                                itemGains[catKey][id] = (itemGains[catKey][id] || 0) + qty;
                                hasItemGains = true;
                            }
                        });
                    }
                }
            });

            const updatedMembers = state.members.map(m => {
                const { updatedMember, logs } = CharacterController.processTurn(m, currentYear, isYearIncrement);
                turnLogs.push(...logs);
                return updatedMember;
            });

            if (Math.random() > 0.6) {
                newEvents.push(EventController.generateNextEvent({ ...state, members: updatedMembers, regions: updatedRegions, buildings: updatedBuildings, inventory: finalInventory }));
            }

            setState(prev => {
                if (hasItemGains) {
                    Object.keys(itemGains).forEach(cat => {
                        const typedCat = cat as keyof Inventory;
                        if (typedCat === 'paper') return;
                        Object.entries(itemGains[typedCat]).forEach(([id, qty]) => {
                            const itemId = parseInt(id);
                            finalInventory[typedCat][itemId] = (finalInventory[typedCat][itemId] || 0) + (qty as number);
                        });
                    });
                }

                return {
                    ...prev,
                    year: isYearIncrement ? prev.year + 1 : prev.year,
                    season: nextSeason,
                    members: updatedMembers,
                    regions: updatedRegions,
                    buildings: updatedBuildings,
                    spiritStones: prev.spiritStones + 50 + guardStones,
                    merit: prev.merit + 2 + guardMerit,
                    inventory: finalInventory,
                    logs: [...turnLogs, ...prev.logs].slice(0, 30)
                };
            });

            if (newEvents.length > 0) setPendingEvents(newEvents);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (pendingEvents.length === 0) return;
        const currentEvent = pendingEvents[0];
        const updates = EventController.processEventChoice(state, currentEvent, choiceKey);

        setState(prev => ({ ...prev, ...updates }));
        setPendingEvents(prev => prev.slice(1));
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean, usedPillId?: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;
            const { updatedMember, log } = CharacterController.breakthrough(member, success, prev.year, usedPillId);
            return {
                ...prev,
                members: prev.members.map(m => m.id === memberId ? updatedMember : m),
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [log, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') setIsManagementVisible(true);
        else setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (!info || state.spiritStones < info.baseCost) return;

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, {
                id: `${type}_${Date.now()}`,
                type,
                level: 1,
                assignedMemberId: null,
                assignedMemberIds: type === 'CultivationRoom' ? Array(12).fill(null) : undefined,
                isFinished: false,
                turnsRemaining: info.baseTurns
            }],
            logs: [`【营造】决定在家族祖地营造 ${info.name}，扣除灵石 ${info.baseCost}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleCancelBuilding = (id: string) => {
        const building = state.buildings.find(b => b.id === id);
        if (!building || building.isFinished) return;
        const info = BUILDING_TYPES[building.type];

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + info.baseCost,
            buildings: prev.buildings.filter(b => b.id !== id),
            logs: [`【营造】取消了 ${info.name} 的营造计划，返还灵石 ${info.baseCost}。`, ...prev.logs].slice(0, 30)
        }));
    };

    return (
        <div className="h-full w-full flex flex-col bg-bg-main text-text-main overflow-hidden select-none font-sans">
            <header className="h-16 bg-bg-panel border-b border-border-soft flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="font-serif font-h1 text-accent-gold tracking-[0.2em]">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-8 items-center border-l border-border-soft pl-8">
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">灵石</span>
                            <span className="font-value text-accent-gold">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">功德</span>
                            <span className="font-value text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">岁时</span>
                            <span className="font-value text-text-main">{state.year}载 · {SEASON_NAMES[state.season]}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-bg-main border border-border-soft text-text-muted rounded-sm font-caption font-bold hover:border-accent-jade transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-sm border transition-all font-caption font-bold ${isDashboardVisible ? 'bg-accent-jade/20 border-accent-jade text-accent-jade' : 'bg-bg-main border-border-soft text-text-disabled'}`}>📜 族谱</button>
                    <button onClick={handleNextTurn} disabled={isProcessing || pendingEvents.length > 0} className="bg-accent-jade hover:brightness-110 disabled:opacity-30 text-bg-main px-8 py-2 rounded-sm font-sans font-body font-bold transition-all shadow-lg">{isProcessing ? '推演中' : '岁时轮转'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-bg-main">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        reputation={state.factionReputation}
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-300 bg-bg-panel/95 border border-border-soft rounded-sm shadow-2xl z-20 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-80 h-64'}`}>
                        <div 
                            className="flex justify-between items-center px-4 py-2 border-b border-border-soft bg-bg-main/50 shrink-0 cursor-pointer group hover:bg-bg-panel/80 transition-all" 
                            onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}
                        >
                            <span className="font-sans font-caption font-bold text-text-muted group-hover:text-text-main transition-colors">族史摘要</span>
                            <div className="flex items-center gap-3">
                                <span className={`text-[10px] text-accent-gold transition-transform duration-300 ${isConsoleCollapsed ? '-rotate-180' : 'rotate-0'}`}>
                                    ▼
                                </span>
                            </div>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="font-sans font-caption text-text-muted leading-relaxed border-b border-border-soft/30 pb-2">
                                        <span className="text-accent-jade mr-2">◈</span> {log}
                                    </p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-border-soft flex flex-col shrink-0">
                        <ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} onOpenBreakthrough={(id) => setBreakingMemberId(id)} onContributeItem={handleContributeItem} />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={(id, u) => setState(p => ({ ...p, buildings: p.buildings.map(b => b.id === id ? { ...b, ...u } : b) }))} 
                    onUpdateInventory={handleUpdateInventory}
                    onAddBuilding={handleAddBuilding} 
                    onCancelBuilding={handleCancelBuilding}
                    onAssignBuilding={(b, m, idx) => setState(p => ({ 
                        ...p, 
                        buildings: p.buildings.map(build => {
                            let nextBuild = { ...build };
                            // 清理：如果该成员已在其他槽位，则清空
                            if (m !== null) {
                                if (nextBuild.assignedMemberId === m) nextBuild.assignedMemberId = null;
                                if (nextBuild.assignedMemberIds) {
                                    nextBuild.assignedMemberIds = nextBuild.assignedMemberIds.map(id => id === m ? null : id);
                                }
                            }

                            // 赋值：指派到目标槽位
                            if (build.id === b) {
                                if (idx === undefined) {
                                    nextBuild.assignedMemberId = m;
                                } else {
                                    const newIds = [...(nextBuild.assignedMemberIds || [])];
                                    while (newIds.length <= idx) newIds.push(null);
                                    newIds[idx] = m;
                                    nextBuild.assignedMemberIds = newIds;
                                }
                            }
                            return nextBuild;
                        }) 
                    }))} 
                    onAssignItem={handleAssignItem}
                    onClose={() => setIsManagementVisible(false)} 
                />
            )}

            {pendingEvents.length > 0 && (
                <EventModal event={pendingEvents[0]} onChoice={handleChoice} />
            )}

            {breakingMemberId && (
                <BreakthroughModal 
                    member={state.members.find(m => m.id === breakingMemberId)!}
                    onClose={() => setBreakingMemberId(null)}
                    onAttempt={(success, pillId) => handleBreakthroughAttempt(breakingMemberId, success, pillId)}
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo } from 'react';
import { ClanMember, Building, Realm } from '../../../../types';
import { REALM_ORDER } from '../../../../constants';

interface Props {
    building: Building;
    members: ClanMember[];
    alreadyAssignedIds: string[];
    onAssignBuilding: (buildingId: string, memberId: string | null, slotIndex?: number) => void;
}

const CultivationRoomTab: React.FC<Props> = ({ building, members, alreadyAssignedIds, onAssignBuilding }) => {
    const [selectedSlotIdx, setSelectedSlotIdx] = useState<number | null>(null);
    const [showMemberSelect, setShowMemberSelect] = useState(false);

    const aliveMembers = members.filter(m => m.status !== 'dead' && m.family === '望月李氏');

    // 密室配置：甲乙丙三等
    const TIERS = [
        { id: 'Jia', name: '甲等', bonus: 1.5, color: 'text-amber-500', border: 'border-amber-600/30', bg: 'bg-amber-900/5', dot: 'bg-amber-500' },
        { id: 'Yi', name: '乙等', bonus: 1.25, color: 'text-blue-500', border: 'border-blue-600/30', bg: 'bg-blue-900/5', dot: 'bg-blue-500' },
        { id: 'Bing', name: '丙等', bonus: 1.1, color: 'text-emerald-500', border: 'border-emerald-600/30', bg: 'bg-emerald-900/5', dot: 'bg-emerald-500' }
    ];

    // 等级排列：天(0), 地(1), 玄(2), 黄(3)
    const SUB_GRADES = ['天', '地', '玄', '黄'];

    // 判断逻辑：1级开黄(idx 3)，2级开玄(idx 2)，3级开地(idx 1)，4级开天(idx 0)
    // 解锁条件： (3 - gIdx) < building.level
    const isSlotUnlocked = (gIdx: number) => {
        return (3 - gIdx) < building.level;
    };

    const assignedIds = useMemo(() => {
        const base = building.assignedMemberIds || [];
        const full = Array(12).fill(null);
        base.forEach((id, i) => { if (i < 12) full[i] = id; });
        return full;
    }, [building.assignedMemberIds]);

    const selectableMembers = useMemo(() => {
        // 允许选择所有非凡人族人，即便已分配，最后一次指派会触发位置更新
        return aliveMembers
            .filter(m => m.realm !== Realm.Mortal)
            .sort((a, b) => {
                const realmA = REALM_ORDER.indexOf(a.realm);
                const realmB = REALM_ORDER.indexOf(b.realm);
                if (realmB !== realmA) return realmB - realmA;
                return b.subRealm - a.subRealm;
            });
    }, [aliveMembers]);

    const handleSlotClick = (idx: number) => {
        setSelectedSlotIdx(idx);
        setShowMemberSelect(true);
    };

    const handleSelect = (memberId: string | null) => {
        if (selectedSlotIdx !== null) {
            onAssignBuilding(building.id, memberId, selectedSlotIdx);
        }
        setShowMemberSelect(false);
    };

    return (
        <div className="flex gap-6 h-full animate-fade-in max-w-7xl mx-auto overflow-hidden">

            {/* 左侧：灵脉与供能面板 */}
            <div className="w-64 shrink-0 flex flex-col gap-6">
                <div className="p-5 bg-black/40 border border-emerald-900/20 rounded shadow-xl flex flex-col">
                    <h3 className="text-emerald-500 font-bold text-[13px] mb-6 flex items-center gap-2 border-b border-emerald-900/10 pb-2">
                        <span>💠</span> 灵脉概况
                    </h3>

                    <div className="space-y-4">
                        <div className="relative h-20 w-full rounded bg-emerald-900/10 border border-emerald-500/20 overflow-hidden flex flex-col items-center justify-center">
                            <div className="absolute inset-0 bg-gradient-to-b from-emerald-500/5 to-transparent animate-pulse"></div>
                            <span className="text-[10px] text-emerald-500 font-bold tracking-widest uppercase">微型灵脉 (初阶)</span>
                            <span className="text-[9px] text-gray-600 mt-1">灵气活跃度: 盈满</span>
                        </div>

                        <div className="space-y-1.5">
                            <div className="flex justify-between items-center text-[10px]">
                                <span className="text-gray-500 font-medium">地脉基础加成</span>
                                <span className="text-emerald-500 font-bold">+25%</span>
                            </div>
                            <div className="flex justify-between items-center text-[10px]">
                                <span className="text-gray-500 font-medium">灵石聚灵加成</span>
                                <span className="text-yellow-600">待启用</span>
                            </div>
                        </div>

                        <div className="pt-4 border-t border-white/5">
                            <button className="w-full py-2.5 bg-yellow-900/20 border border-yellow-700/30 text-yellow-500 rounded text-[10px] font-bold hover:bg-yellow-900/40 transition-all">
                                ✨ 消耗 100 灵石聚灵
                            </button>
                            <p className="text-[8px] text-gray-700 mt-2 text-center italic">瞬间为所有闭关者提供修为补偿</p>
                        </div>
                    </div>
                </div>

                <div className="p-5 bg-black/40 border border-blue-900/20 rounded shadow-xl flex-1 overflow-hidden flex flex-col">
                    <h3 className="text-blue-500 font-bold text-[13px] mb-4 border-b border-blue-900/10 pb-2 flex items-center gap-2">
                        <span>🏺</span> 修炼灵物
                    </h3>
                    <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2">
                        <div className="p-2 border border-white/5 rounded bg-white/5 flex items-center gap-2 opacity-30 grayscale">
                            <span className="text-lg">🍵</span>
                            <div className="flex flex-col">
                                <span className="text-[9px] text-gray-500 font-bold">悟道茶</span>
                                <span className="text-[7px] text-gray-700">未持有</span>
                            </div>
                        </div>
                        <div className="p-2 border border-blue-900/20 rounded bg-blue-900/5 flex items-center gap-2">
                            <span className="text-lg">🕯️</span>
                            <div className="flex flex-col">
                                <span className="text-[9px] text-blue-400 font-bold">静心檀香</span>
                                <span className="text-[7px] text-gray-500">瓶颈突破率 +2%</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            {/* 右侧：密室矩阵 */}
            <div className="flex-1 bg-black/40 border border-white/5 rounded p-6 flex flex-col overflow-hidden">
                <div className="flex justify-between items-center mb-8">
                    <h4 className="text-gray-300 font-bold text-sm tracking-widest flex items-center gap-2 opacity-80">
                        <span>🏛️</span> 密室群落布局
                    </h4>
                    <div className="flex gap-4 text-[10px] font-bold">
                        <span className="flex items-center gap-1.5 text-gray-400"><span className="w-2 h-2 rounded-full bg-amber-500 shadow-[0_0_5px_rgba(245,158,11,0.5)]"></span> 甲等</span>
                        <span className="flex items-center gap-1.5 text-gray-400"><span className="w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_5px_rgba(59,130,246,0.5)]"></span> 乙等</span>
                        <span className="flex items-center gap-1.5 text-gray-400"><span className="w-2 h-2 rounded-full bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]"></span> 丙等</span>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 pb-6">
                    {TIERS.map((tier, tIdx) => {
                        // 检查该等级下是否有任何密室已解锁
                        const anyInTierUnlocked = SUB_GRADES.some((_, gIdx) => isSlotUnlocked(gIdx));
                        if (!anyInTierUnlocked) return null;

                        return (
                            <div key={tier.id} className="mb-12 last:mb-0">
                                <div className={`flex items-center gap-3 mb-5 border-l-2 ${tier.color.replace('text', 'border')} pl-3`}>
                                    <span className={`${tier.color} font-bold text-sm tracking-widest`}>{tier.name}·静室区域</span>
                                    <span className="text-[10px] text-gray-600 font-mono opacity-60">经验速率: x{tier.bonus}</span>
                                </div>

                                <div className="grid grid-cols-2 lg:grid-cols-4 gap-5">
                                    {SUB_GRADES.map((grade, gIdx) => {
                                        const slotIdx = tIdx * 4 + gIdx;
                                        const isUnlocked = isSlotUnlocked(gIdx);

                                        // 未解锁的密室不显示
                                        if (!isUnlocked) return null;

                                        const memberId = assignedIds[slotIdx];
                                        const member = aliveMembers.find(m => m.id === memberId);

                                        return (
                                            <div 
                                                key={slotIdx}
                                                onClick={() => handleSlotClick(slotIdx)}
                                                className={`relative h-44 rounded-lg border flex flex-col items-center justify-center transition-all overflow-hidden group
                                                    ${member 
                                                        ? `${tier.border} ${tier.bg} shadow-lg cursor-pointer hover:border-white/20` 
                                                        : 'bg-black/60 border-white/5 border-dashed cursor-pointer hover:border-white/10'}
                                                `}
                                            >
                                                {/* 编号标注 */}
                                                <div className={`absolute top-3 left-3 text-[9px] font-bold px-1.5 py-0.5 rounded bg-black/60 border border-white/5 z-20 ${member ? tier.color : 'text-gray-600'}`}>
                                                    {grade}字{tier.name[0]}
                                                </div>

                                                {member ? (
                                                    <div className="flex flex-col items-center animate-fade-in text-center p-2 z-10">
                                                        <div className="w-14 h-14 rounded-full border border-white/10 bg-black/40 flex items-center justify-center text-2xl mb-3 shadow-[inset_0_0_15px_rgba(0,0,0,0.5)]">🧘</div>
                                                        <p className={`text-xs font-bold ${tier.color}`}>{member.name}</p>
                                                        <p className="text-[9px] text-gray-500 mt-1 font-medium">{member.realm}{member.subRealm}层</p>
                                                        <div className="mt-2 text-[8px] bg-emerald-500/10 border border-emerald-500/20 px-2 py-0.5 rounded text-emerald-400 animate-pulse">气息流转中</div>
                                                    </div>
                                                ) : (
                                                    <div className="flex flex-col items-center opacity-20 group-hover:opacity-100 transition-all duration-300">
                                                        <span className="text-3xl mb-1">🔘</span>
                                                        <span className="text-[10px] text-gray-600 font-bold uppercase tracking-widest">空置密室</span>
                                                    </div>
                                                )}

                                                {/* 鼠标悬浮光晕 */}
                                                {!member && (
                                                    <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"></div>
                                                )}
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* 成员选择弹窗 */}
            {showMemberSelect && (
                <div className="absolute inset-0 z-[60] bg-black/85 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-[#1a1a1a] border-2 border-emerald-900/30 w-full max-w-md rounded shadow-2xl flex flex-col max-h-[80%] overflow-hidden animate-fade-in" onClick={(e) => e.stopPropagation()}>
                        <div className="p-4 bg-[#121a15] border-b border-emerald-900/20 flex justify-between items-center">
                            <div>
                                <h4 className="text-emerald-500 font-bold text-sm tracking-widest">指派入室</h4>
                                <p className="text-[10px] text-gray-500 mt-0.5 italic">※ 若指派已在其它位置的族人，旧位置将自动清空</p>
                            </div>
                            <button onClick={() => setShowMemberSelect(false)} className="text-gray-500 hover:text-white text-2xl transition-colors font-bold">×</button>
                        </div>
                        <div className="p-2 overflow-y-auto custom-scrollbar flex-1 space-y-1 bg-black/20">
                            {selectedSlotIdx !== null && assignedIds[selectedSlotIdx] && (
                                <button 
                                    onClick={() => handleSelect(null)}
                                    className="w-full p-3 bg-red-950/20 border border-red-900/30 text-red-500 text-xs font-bold hover:bg-red-900/20 mb-2 rounded transition-all"
                                >
                                    撤出密室 (恢复空位)
                                </button>
                            )}
                            {selectableMembers.length > 0 ? selectableMembers.map(member => {
                                const isAssignedSomewhere = alreadyAssignedIds.includes(member.id);
                                const isCurrentSlot = selectedSlotIdx !== null && member.id === assignedIds[selectedSlotIdx];

                                return (
                                    <div 
                                        key={member.id} 
                                        onClick={() => handleSelect(member.id)}
                                        className={`p-3 border rounded transition-all cursor-pointer flex justify-between items-center group
                                            ${isCurrentSlot 
                                                ? 'bg-emerald-900/20 border-emerald-500/50' 
                                                : 'bg-white/5 border-white/5 hover:bg-emerald-900/10 hover:border-emerald-600/30'}`}
                                    >
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded bg-black/40 flex items-center justify-center border border-white/5 text-emerald-500 text-xs font-bold">
                                                {member.name[0]}
                                            </div>
                                            <div className="flex flex-col">
                                                <div className="flex items-center gap-2">
                                                    <span className="text-gray-200 font-bold text-sm">{member.name}</span>
                                                    {isAssignedSomewhere && !isCurrentSlot && (
                                                        <span className="text-[7px] px-1 bg-yellow-900/30 text-yellow-600 border border-yellow-600/20 rounded">他处任职</span>
                                                    )}
                                                </div>
                                                <span className="text-[10px] text-gray-500">{member.realm}{member.subRealm}层</span>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <p className="text-[10px] text-emerald-600 font-bold uppercase">{member.position}</p>
                                            <p className="text-[9px] text-gray-700 mt-1">{member.age} 岁</p>
                                        </div>
                                    </div>
                                );
                            }) : (
                                <div className="py-20 text-center text-gray-600 italic text-xs">暂无符合条件的族人</div>
                            )}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CultivationRoomTab;

import { ClanMember, Realm, RootGrade, TaskType } from '../types';
import { REALM_ORDER } from '../constants';
import { calculateQuarterlyExpGain, getRequiredExp } from '../components/Xiulian/CultivationSystem';

export class CharacterController {
    /**
     * 自动判定并更新灵根等级
     */
    static getAutoRootGrade(roots: ClanMember['roots']): RootGrade {
        const maxRoot = Math.max(roots.gold, roots.wood, roots.water, roots.fire, roots.earth);
        if (maxRoot === 0) return '凡人';
        if (maxRoot <= 2) return '伪灵根';
        if (maxRoot <= 4) return '下品灵根';
        if (maxRoot <= 6) return '中品灵根';
        if (maxRoot <= 8) return '上品灵根';
        return '极品灵根';
    }

    /**
     * 处理修为进度增长，支持跨级升级
     */
    static applyCultivationProgress(member: ClanMember, logs: string[], year: number): ClanMember {
        if (member.realm === Realm.Mortal) return member;

        let nm = { ...member };
        let progress = nm.cultivationProgress;
        let subRealm = nm.subRealm;
        const realmIdx = REALM_ORDER.indexOf(nm.realm);

        let currentReq = getRequiredExp(realmIdx, subRealm);

        // 处理自动连续升级
        while (progress >= currentReq && subRealm < 9) {
            progress -= currentReq;
            subRealm += 1;
            currentReq = getRequiredExp(realmIdx, subRealm);
            logs.push(`【${year}载·晋升】${nm.name} 气息升华，实时突破至 ${nm.realm} ${subRealm}层。`);
        }

        // 处理大圆满瓶颈
        if (subRealm === 9 && progress >= currentReq) {
            progress = currentReq;
            if (member.subRealm < 9 || member.cultivationProgress < currentReq) {
                logs.push(`【${year}载·瓶颈】${nm.name} 触碰天门，已达 ${nm.realm}巅峰之境。`);
            }
        }

        nm.cultivationProgress = progress;
        nm.subRealm = subRealm;
        return nm;
    }

    /**
     * 在世族人的回合逻辑处理
     */
    static processTurn(member: ClanMember, year: number, isYearIncrement: boolean): { updatedMember: ClanMember; logs: string[]; travelTriggered?: boolean } {
        let nm = { ...member };
        let turnLogs: string[] = [];

        if (nm.status === 'dead') return { updatedMember: nm, logs: [] };

        // 1. 寿命增长
        if (isYearIncrement) {
            nm.age += 1;
            if (nm.age >= nm.maxAge) {
                nm.status = 'dead';
                nm.deathYear = year;
                turnLogs.push(`【${year}载·春】${nm.name} 寿元耗尽，溘然长逝。`);
                return { updatedMember: nm, logs: turnLogs };
            }
        }

        // 2. 伤势康复逻辑
        if (nm.status === 'injured') {
            nm.assignment = 'Recovery';
            if (Math.random() > 0.4) {
                nm.status = 'healthy';
                nm.assignment = 'Idle'; // 康复后重置为闲置
                turnLogs.push(`【${year}载】${nm.name} 伤势痊愈，重回家族待命。`);
            }
        }

        // 3. 修为增长逻辑
        const hasRoots = Object.values(nm.roots).some(v => v > 0);
        if (hasRoots && nm.realm !== Realm.Mortal) {
            const baseGain = calculateQuarterlyExpGain(nm);
            let multiplier = 0.1;

            switch (nm.assignment) {
                case 'Cultivation': multiplier = 1.0; break;
                case 'Research':
                case 'Alchemy':
                case 'Smithing': multiplier = 0.6; break;
                case 'Mission': multiplier = 0.4; break;
                case 'Recovery': multiplier = 0.2; break;
                case 'Travel':
                case 'Idle': multiplier = 0.1; break;
                default: multiplier = 0.1;
            }

            nm.cultivationProgress += baseGain * multiplier;
            nm = this.applyCultivationProgress(nm, turnLogs, year);
        } else if (nm.realm === Realm.Mortal) {
            nm.assignment = 'Idle';
        }

        // 4. 游历触发概率
        const travelTriggered = nm.status === 'healthy' && nm.assignment === 'Cultivation' && Math.random() < 0.05;

        return { updatedMember: nm, logs: turnLogs, travelTriggered };
    }

    /**
     * 处理外部手动更新（如服用丹药、分配任务）
     */
    static updateMember(member: ClanMember, updates: Partial<ClanMember>, year: number): { updatedMember: ClanMember; logs: string[] } {
        let nm = { ...member, ...updates };
        let logs: string[] = [];

        // 自动灵根评级
        if (updates.roots) {
            const newGrade = this.getAutoRootGrade(nm.roots);
            if (nm.rootGrade !== newGrade) {
                logs.push(`【${year}载·造化】${nm.name} 灵根升华，晋升为 ${newGrade}。`);
                nm.rootGrade = newGrade;
            }
        }

        // 自动修为结算
        if (updates.cultivationProgress !== undefined) {
            nm = this.applyCultivationProgress(nm, logs, year);
        }

        return { updatedMember: nm, logs };
    }

    /**
     * 执行大境界突破
     * @param member 族人对象
     * @param success 突破是否成功
     * @param year 当前年份
     * @param usedPillId 可选：使用的丹药ID
     */
    static breakthrough(member: ClanMember, success: boolean, year: number, usedPillId?: number): { updatedMember: ClanMember; log: string } {
        let nm = { ...member };

        // 1. 消耗丹药
        if (usedPillId) {
            const newPills = { ...nm.personalInventory.pills };
            if (newPills[usedPillId] > 0) {
                newPills[usedPillId]--;
                if (newPills[usedPillId] === 0) delete newPills[usedPillId];
            }
            nm.personalInventory = { ...nm.personalInventory, pills: newPills };
        }

        // 2. 突破因果判定
        if (success) {
            const currentIdx = REALM_ORDER.indexOf(nm.realm);
            const nextRealm = REALM_ORDER[currentIdx + 1] || Realm.YuanShen;
            return {
                updatedMember: {
                    ...nm,
                    realm: nextRealm,
                    subRealm: 1,
                    cultivationProgress: 0,
                    maxAge: nm.maxAge + 100,
                    legacyPoints: (nm.legacyPoints || 0) + 10
                },
                log: `【${year}载·突破】${nm.name} 气息贯通天地，成功晋升至 ${nextRealm}。`
            };
        } else {
            return {
                updatedMember: {
                    ...nm,
                    subRealm: 8,
                    cultivationProgress: 0,
                    status: 'injured',
                    assignment: 'Recovery'
                },
                log: `【${year}载·突破】${nm.name} 叩问天门失败，遭灵力反噬，修为跌落。`
            };
        }
    }
}

import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory, GameEvent, TaskType } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, ALL_ITEM_DETAILS, RECIPES } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import { CharacterController } from './services/CharacterController';
import { EventController } from './services/EventController';
import ClanDashboard from './components/MembersPanel/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement/ClanManagement';
import BreakthroughModal from './components/Xiulian/BreakthroughModal';
import EventModal from './components/events/EventModal';

const SEASON_NAMES = ['', '春', '夏', '秋', '冬'];

const App: React.FC = () => {
    const [state, setState] = useState<GameState>(() => {
        const initializedMembers = INITIAL_MEMBERS.map(m => ({
            ...m,
            rootGrade: CharacterController.getAutoRootGrade(m.roots)
        })) as ClanMember[];

        return {
            year: 1,
            season: 1,
            spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
            merit: CLAN_MASTER_REGISTRY.merit,
            luck: CLAN_MASTER_REGISTRY.luck,
            members: initializedMembers,
            regions: INITIAL_REGIONS,
            buildings: [],
            inventory: CLAN_MASTER_REGISTRY.inventory,
            currentRegionId: '',
            logs: ["太平历初，望月李氏在此立基。"],
            heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
            unlockedPositions: ['家主', '弟子'],
            flags: {},
            eventQueue: [],
            factionReputation: { '魏家': 50, '邵家': 50, '北寒宗': 50 } 
        };
    });

    const [pendingEvents, setPendingEvents] = useState<GameEvent[]>([]);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === id);
            if (!member) return prev;
            const { updatedMember, logs } = CharacterController.updateMember(member, updates, prev.year);
            let updatedMembers = prev.members.map(m => m.id === id ? updatedMember : m);
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }
            return {
                ...prev,
                members: updatedMembers,
                logs: logs.length > 0 ? [...logs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleUpdateInventory = (updates: Partial<Inventory>) => {
        setState(prev => ({
            ...prev,
            inventory: { ...prev.inventory, ...updates }
        }));
    };

    const handleAssignItem = (memberId: string, itemId: number, category: string, quantity: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            const itemDetail = ALL_ITEM_DETAILS[itemId] as any;
            const catKey = category as keyof Inventory;

            if (!member || !itemDetail || (prev.inventory[catKey] as any)[itemId] < quantity) return prev;

            const newClanInventory = { ...prev.inventory };
            (newClanInventory[catKey] as any)[itemId] -= quantity;
            if ((newClanInventory[catKey] as any)[itemId] === 0) delete (newClanInventory[catKey] as any)[itemId];

            const newMemberInventory = { ...member.personalInventory };
            (newMemberInventory[catKey] as any)[itemId] = ((newMemberInventory[catKey] as any)[itemId] || 0) + quantity;

            const updatedMembers = prev.members.map(m => 
                m.id === memberId ? { ...m, personalInventory: newMemberInventory } : m
            );

            return {
                ...prev,
                inventory: newClanInventory,
                members: updatedMembers,
                logs: [`【分配】家族将 ${itemDetail.name} x${quantity} 分配给了 ${member.name}。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleContributeItem = (memberId: string, itemId: number, category: string, quantity: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            const catKey = category as keyof Inventory;
            const currentQty = (member.personalInventory[catKey] as any)[itemId] || 0;
            if (currentQty < quantity) return prev;

            const newMemberInventory = { ...member.personalInventory };
            (newMemberInventory[catKey] as any)[itemId] -= quantity;
            if ((newMemberInventory[catKey] as any)[itemId] <= 0) {
                delete (newMemberInventory[catKey] as any)[itemId];
            }

            const newClanInventory = { ...prev.inventory };
            if (catKey !== 'paper') {
                (newClanInventory[catKey] as any)[itemId] = ((newClanInventory[catKey] as any)[itemId] || 0) + quantity;
            }

            const itemDetail = ALL_ITEM_DETAILS[itemId] as any;

            return {
                ...prev,
                inventory: newClanInventory,
                members: prev.members.map(m => m.id === memberId ? { ...m, personalInventory: newMemberInventory } : m),
                logs: [`【上交】${member.name} 将 ${itemDetail?.name || '物品'} x${quantity} 上交给家族。`, ...prev.logs].slice(0, 30)
            };
        });
    };

    const handleNextTurn = async () => {
        setIsProcessing(true);
        await new Promise(resolve => setTimeout(resolve, 800));

        try {
            let turnLogs: string[] = [];
            let newEvents: GameEvent[] = [];
            let finalInventory = { ...state.inventory };

            const currentYear = state.year;
            const currentSeason = state.season;
            const nextSeason = currentSeason >= 4 ? 1 : currentSeason + 1;
            const isYearIncrement = currentSeason === 4;

            // 建筑与生产进度
            const updatedBuildings = state.buildings.map(b => {
                // 处理建造
                if (!b.isFinished) {
                    const rem = b.turnsRemaining - 1;
                    if (rem <= 0) {
                        turnLogs.push(`【${currentYear}载·${SEASON_NAMES[currentSeason]}】${BUILDING_TYPES[b.type].name} 营造完成。`);
                        return { ...b, isFinished: true, turnsRemaining: 0 };
                    }
                    return { ...b, turnsRemaining: rem };
                }

                // 处理生产 (炼丹/炼器)
                if (b.activeProduction) {
                    const rem = b.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const recipe = [...RECIPES.Alchemy, ...RECIPES.Smithing].find(r => r.id === b.activeProduction!.recipeId);
                        if (recipe) {
                            const productDetail = ALL_ITEM_DETAILS[recipe.productId] as any;
                            const catKey = productDetail.category === 'pill' ? 'pills' : 'weapons';
                            finalInventory[catKey][recipe.productId] = (finalInventory[catKey][recipe.productId] || 0) + 1;
                            turnLogs.push(`【${currentYear}载·成品】${BUILDING_TYPES[b.type].name} 传来阵阵异香，${productDetail.name} 炼制成功！`);
                        }
                        return { ...b, activeProduction: undefined };
                    }
                    return { ...b, activeProduction: { ...b.activeProduction, turnsRemaining: rem } };
                }
                return b;
            });

            const updatedRegions = state.regions.map(r => {
                let nr = { ...r };
                if (nr.activeMission) {
                    const rem = nr.activeMission.turnsRemaining - 1;
                    if (rem <= 0) {
                        const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                        if (member) {
                            const missionEvent = EventController.generateMissionResult(member, nr, currentYear);
                            newEvents.push(missionEvent);
                        }
                        nr.activeMission = undefined;
                    } else {
                        nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                    }
                }
                return nr;
            });

            let guardStones = 0;
            let guardMerit = 0;
            const itemGains: any = { herbs: {}, minerals: {}, pills: {}, weapons: {}, methods: {}, scrolls: {} };
            let hasItemGains = false;

            state.regions.forEach(region => {
                if (region.guardMemberId && region.production) {
                    if (region.production.stones) guardStones += region.production.stones;
                    if (region.production.merit) guardMerit += region.production.merit;
                    if (region.production.items) {
                        Object.entries(region.production.items).forEach(([idStr, qty]) => {
                            const id = parseInt(idStr);
                            const detail = ALL_ITEM_DETAILS[id];
                            if (detail) {
                                const cat = (detail as any).category;
                                const catKey = cat === 'herb' ? 'herbs' :
                                               cat === 'mineral' ? 'minerals' :
                                               cat === 'pill' ? 'pills' :
                                               cat === 'weapon' ? 'weapons' :
                                               cat === 'method' ? 'methods' : 'scrolls';

                                itemGains[catKey][id] = (itemGains[catKey][id] || 0) + qty;
                                hasItemGains = true;
                            }
                        });
                    }
                }
            });

            const updatedMembers = state.members.map(m => {
                const { updatedMember, logs } = CharacterController.processTurn(m, currentYear, isYearIncrement);
                turnLogs.push(...logs);
                return updatedMember;
            });

            if (Math.random() > 0.6) {
                newEvents.push(EventController.generateNextEvent({ ...state, members: updatedMembers, regions: updatedRegions, buildings: updatedBuildings, inventory: finalInventory }));
            }

            setState(prev => {
                if (hasItemGains) {
                    Object.keys(itemGains).forEach(cat => {
                        const typedCat = cat as keyof Inventory;
                        if (typedCat === 'paper') return;
                        Object.entries(itemGains[typedCat]).forEach(([id, qty]) => {
                            const itemId = parseInt(id);
                            finalInventory[typedCat][itemId] = (finalInventory[typedCat][itemId] || 0) + (qty as number);
                        });
                    });
                }

                return {
                    ...prev,
                    year: isYearIncrement ? prev.year + 1 : prev.year,
                    season: nextSeason,
                    members: updatedMembers,
                    regions: updatedRegions,
                    buildings: updatedBuildings,
                    spiritStones: prev.spiritStones + 50 + guardStones,
                    merit: prev.merit + 2 + guardMerit,
                    inventory: finalInventory,
                    logs: [...turnLogs, ...prev.logs].slice(0, 30)
                };
            });

            if (newEvents.length > 0) setPendingEvents(newEvents);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (pendingEvents.length === 0) return;
        const currentEvent = pendingEvents[0];
        const updates = EventController.processEventChoice(state, currentEvent, choiceKey);

        setState(prev => ({ ...prev, ...updates }));
        setPendingEvents(prev => prev.slice(1));
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean, usedPillId?: number) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;
            const { updatedMember, log } = CharacterController.breakthrough(member, success, prev.year, usedPillId);
            return {
                ...prev,
                members: prev.members.map(m => m.id === memberId ? updatedMember : m),
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [log, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') setIsManagementVisible(true);
        else setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (!info || state.spiritStones < info.baseCost) return;

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, {
                id: `${type}_${Date.now()}`,
                type,
                level: 1,
                assignedMemberId: null,
                assignedMemberIds: type === 'CultivationRoom' ? Array(12).fill(null) : undefined,
                isFinished: false,
                turnsRemaining: info.baseTurns
            }],
            logs: [`【营造】决定在家族祖地营造 ${info.name}，扣除灵石 ${info.baseCost}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleCancelBuilding = (id: string) => {
        const building = state.buildings.find(b => b.id === id);
        if (!building || building.isFinished) return;
        const info = BUILDING_TYPES[building.type];

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + info.baseCost,
            buildings: prev.buildings.filter(b => b.id !== id),
            logs: [`【营造】取消了 ${info.name} 的营造计划，返还灵石 ${info.baseCost}。`, ...prev.logs].slice(0, 30)
        }));
    };

    return (
        <div className="h-full w-full flex flex-col bg-bg-main text-text-main overflow-hidden select-none font-sans">
            <header className="h-16 bg-bg-panel border-b border-border-soft flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="font-serif font-h1 text-accent-gold tracking-[0.2em]">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-8 items-center border-l border-border-soft pl-8">
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">灵石</span>
                            <span className="font-value text-accent-gold">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">功德</span>
                            <span className="font-value text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="font-caption text-text-disabled">岁时</span>
                            <span className="font-value text-text-main">{state.year}载 · {SEASON_NAMES[state.season]}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-bg-main border border-border-soft text-text-muted rounded-sm font-caption font-bold hover:border-accent-jade transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-sm border transition-all font-caption font-bold ${isDashboardVisible ? 'bg-accent-jade/20 border-accent-jade text-accent-jade' : 'bg-bg-main border-border-soft text-text-disabled'}`}>📜 族谱</button>
                    <button onClick={handleNextTurn} disabled={isProcessing || pendingEvents.length > 0} className="bg-accent-jade hover:brightness-110 disabled:opacity-30 text-bg-main px-8 py-2 rounded-sm font-sans font-body font-bold transition-all shadow-lg">{isProcessing ? '推演中' : '岁时轮转'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-bg-main">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        reputation={state.factionReputation}
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-300 bg-bg-panel/95 border border-border-soft rounded-sm shadow-2xl z-20 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-80 h-64'}`}>
                        <div 
                            className="flex justify-between items-center px-4 py-2 border-b border-border-soft bg-bg-main/50 shrink-0 cursor-pointer group hover:bg-bg-panel/80 transition-all" 
                            onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}
                        >
                            <span className="font-sans font-caption font-bold text-text-muted group-hover:text-text-main transition-colors">族史摘要</span>
                            <div className="flex items-center gap-3">
                                <span className={`text-[10px] text-accent-gold transition-transform duration-300 ${isConsoleCollapsed ? '-rotate-180' : 'rotate-0'}`}>
                                    ▼
                                </span>
                            </div>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.map((log, i) => (
                                    <p key={i} className="font-sans font-caption text-text-muted leading-relaxed border-b border-border-soft/30 pb-2">
                                        <span className="text-accent-jade mr-2">◈</span> {log}
                                    </p>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-border-soft flex flex-col shrink-0">
                        <ClanDashboard state={state} onUpdateMember={handleUpdateMember} onAddMember={() => {}} onOpenBreakthrough={(id) => setBreakingMemberId(id)} onContributeItem={handleContributeItem} />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={(id, u) => setState(p => ({ ...p, buildings: p.buildings.map(b => b.id === id ? { ...b, ...u } : b) }))} 
                    onUpdateInventory={handleUpdateInventory}
                    onAddBuilding={handleAddBuilding} 
                    onCancelBuilding={handleCancelBuilding}
                    onAssignBuilding={(bId, mId, slotIdx) => setState(p => {
                        const targetBuilding = p.buildings.find(b => b.id === bId);
                        if (!targetBuilding) return p;

                        // 定义各建筑对应的任务
                        const getTaskForBuilding = (type: string): TaskType => {
                            if (type === 'CultivationRoom') return 'Cultivation';
                            if (type === 'AlchemyRoom') return 'Alchemy';
                            if (type === 'Smithy') return 'Smithing';
                            if (type === 'Library') return 'Research';
                            return 'Idle';
                        };

                        const newTask = getTaskForBuilding(targetBuilding.type);

                        // 1. 预先找出会被踢出的族人（旧占坑者）
                        let evictedMemberId: string | null = null;
                        if (slotIdx === undefined) {
                            evictedMemberId = targetBuilding.assignedMemberId;
                        } else {
                            evictedMemberId = targetBuilding.assignedMemberIds?.[slotIdx] || null;
                        }

                        // 2. 更新成员列表状态
                        const nextMembers = p.members.map(mem => {
                            // 被新指派的族人 -> 切换到建筑对应任务
                            if (mId !== null && mem.id === mId) {
                                return { ...mem, assignment: newTask };
                            }
                            // 被踢出的族人（且不是正在重新指派的那个） -> 恢复 Idle
                            if (evictedMemberId !== null && mem.id === evictedMemberId && mem.id !== mId) {
                                return { ...mem, assignment: 'Idle' as TaskType };
                            }
                            // 全局清理逻辑：如果族人之前在其他建筑，在接下来 building map 中会被清空
                            // 为了严谨，这里不做预测，只根据上面的 eviction 和 assignment 更新。
                            // 但由于 App 逻辑中会在下面清除 mId 的旧位，我们需要确保该族人在旧位被清除后，
                            // 最终是由上面的 "if mem.id === mId" 设置为正确状态。
                            return mem;
                        });

                        // 3. 更新建筑列表
                        const nextBuildings = p.buildings.map(build => {
                            let nb = { ...build };

                            // 之前的逻辑：清理目标成员在全服的所有指派信息
                            if (mId !== null) {
                                if (nb.assignedMemberId === mId) {
                                    nb.assignedMemberId = null;
                                }
                                if (nb.assignedMemberIds) {
                                    nb.assignedMemberIds = nb.assignedMemberIds.map(id => id === mId ? null : id);
                                }
                            }

                            // 赋值：指派到目标槽位
                            if (nb.id === bId) {
                                if (slotIdx === undefined) {
                                    nb.assignedMemberId = mId;
                                } else {
                                    const newIds = [...(nb.assignedMemberIds || [])];
                                    while (newIds.length <= slotIdx) newIds.push(null);
                                    newIds[slotIdx] = mId;
                                    nb.assignedMemberIds = newIds;
                                }
                            }
                            return nb;
                        });

                        return {
                            ...p,
                            members: nextMembers,
                            buildings: nextBuildings
                        };
                    })} 
                    onAssignItem={handleAssignItem}
                    onClose={() => setIsManagementVisible(false)} 
                />
            )}

            {pendingEvents.length > 0 && (
                <EventModal event={pendingEvents[0]} onChoice={handleChoice} />
            )}

            {breakingMemberId && (
                <BreakthroughModal 
                    member={state.members.find(m => m.id === breakingMemberId)!}
                    onClose={() => setBreakingMemberId(null)}
                    onAttempt={(success, pillId) => handleBreakthroughAttempt(breakingMemberId, success, pillId)}
                />
            )}
        </div>
    );
};

